// ============================================================================
// LOAD BRAND MEMORY - Creative MCP V6
// ============================================================================

return [{
  json: {
    brand_id: "ak_v6_demo",
    brand_name: "The Hive",

    visual_identity: {
      style: "Minimalist, Tech, Neon Accents",
      mood: "Bold, Futuristic, Premium",
      hex_colors: {
        primary: "#000000",
        secondary: "#FFFFFF",
        accent_1: "#FF00FF",
        accent_2: "#00FFFF",
        accent_3: "#FFD700",
        danger: "#EF4444",
        success: "#10B981"
      },
      fonts: {
        headings: "Inter",
        body: "Inter",
        display: "Space Grotesk"
      },
      design_rules: [
        "Fond sombre obligatoire (noir ou gradient)",
        "Texte blanc ou neon sur fond sombre",
        "Accent magenta pour les CTA",
        "Max 3 elements visuels par image",
        "Espace negatif min 30%"
      ]
    },

    tone_of_voice: {
      personality: "Bold, Direct, Urgent",
      formality: "vous",
      writing_style: {
        sentence_length: "court",
        power_words: true,
        questions: true,
        numbers: true
      },
      power_words: ["Instant", "Garanti", "Exclusif", "Limite", "Maintenant", "Gratuit", "Prouve", "Secret", "Nouveau", "Decouvrez", "Enfin", "Stop"],
      banned_words: ["pas cher", "discount", "promo", "soldes", "meilleur", "numero 1", "leader", "revolutionnaire", "magique", "miracle"]
    },

    platform_specs: {
      meta_feed: { aspect_ratio: "1:1", dimensions: "1080x1080", max_text_ratio: 0.20 },
      meta_story: { aspect_ratio: "9:16", dimensions: "1080x1920", max_text_ratio: 0.20 },
      meta_reel: { aspect_ratio: "9:16", dimensions: "1080x1920", max_text_ratio: 0.15 },
      linkedin_feed: { aspect_ratio: "1.91:1", dimensions: "1200x628", max_text_ratio: 0.25 },
      youtube_thumbnail: { aspect_ratio: "16:9", dimensions: "1280x720", max_text_ratio: 0.30 }
    },

    products: [
      { id: "hive_pro", name: "The Hive Pro", price: "99EUR/mois", tagline: "4 agents IA pour le prix d'un outil" },
      { id: "hive_enterprise", name: "The Hive Enterprise", price: "Sur devis", tagline: "Solution sur-mesure pour grandes equipes" }
    ],

    creative_learnings: [
      { insight: "Visages humains +35% CTR", confidence: 0.85 },
      { insight: "Chiffres dans titre +28% engagement", confidence: 0.82 },
      { insight: "Questions directes +22% click", confidence: 0.78 }
    ]
  }
}];

// ============================================================================
// GHOST BUSTER - Anti-Hallucination Image Sanitizer
// Creative MCP V6 - CRITICAL SECURITY NODE
// ============================================================================

const brandMemory = $('Load Brand Memory').item.json;
const userInput = $('Webhook Trigger').item.json;

// ─────────────────────────────────────────────────────────────────────────
// GHOST BUSTER: Clean image_base64 to prevent AI hallucination
// If image is "null", "undefined", empty, or < 100 chars -> force to null
// ─────────────────────────────────────────────────────────────────────────
let rawImage = userInput.body?.image_base64 || userInput.image_base64 || null;
let cleanedImage = null;
let hasValidImage = false;

// Ghost Buster Logic
if (rawImage !== null && rawImage !== undefined) {
  const imageStr = String(rawImage).trim().toLowerCase();

  // Check for ghost values
  const isGhost = (
    imageStr === 'null' ||
    imageStr === 'undefined' ||
    imageStr === '' ||
    imageStr === 'none' ||
    imageStr.length < 100  // Base64 image must be > 100 chars
  );

  if (!isGhost) {
    cleanedImage = rawImage;
    hasValidImage = true;
  }
}

// ─────────────────────────────────────────────────────────────────────────
// DETECT MODE & PLATFORM
// ─────────────────────────────────────────────────────────────────────────
const message = (userInput.body?.message || userInput.message || "").toLowerCase();

let detectedMode = 'production';
const brainstormKeywords = ['idee', 'idees', 'concept', 'brainstorm', 'propose', 'suggere', 'inspiration', 'angle', 'hook'];
const videoKeywords = ['video', 'vidéo', 'reel', 'anime', 'animation', 'motion', 'runway'];
const imageKeywords = ['image', 'visuel', 'photo', 'graphique', 'illustration', 'poster', 'banner'];
const copyKeywords = ['texte', 'copy', 'article', 'blog', 'script', 'redige', 'ecris'];

if (brainstormKeywords.some(kw => message.includes(kw))) {
  detectedMode = 'brainstorming';
} else if (message.length < 15) {
  detectedMode = 'needs_clarification';
}

// Detect content type requested
let contentType = 'mixed';
if (videoKeywords.some(kw => message.includes(kw))) {
  contentType = 'video';
} else if (imageKeywords.some(kw => message.includes(kw))) {
  contentType = 'image';
} else if (copyKeywords.some(kw => message.includes(kw))) {
  contentType = 'copy';
}

// Detect platform
let platform = 'meta_feed';
if (message.includes('story') || message.includes('stories')) platform = 'meta_story';
else if (message.includes('reel')) platform = 'meta_reel';
else if (message.includes('linkedin')) platform = 'linkedin_feed';
else if (message.includes('youtube') || message.includes('thumbnail')) platform = 'youtube_thumbnail';

// ─────────────────────────────────────────────────────────────────────────
// VISION MODE: If valid image, enable vision analysis
// ─────────────────────────────────────────────────────────────────────────
let visionMode = 'disabled';
if (hasValidImage) {
  // Determine vision use case
  if (contentType === 'video') {
    visionMode = 'image_to_video';  // User wants to animate the image
  } else if (contentType === 'copy') {
    visionMode = 'image_to_text';   // User wants copy based on image
  } else {
    visionMode = 'image_analysis';  // General analysis
  }
}

return [{
  json: {
    user_request: {
      message: userInput.body?.message || userInput.message || "Cree une pub",
      session_id: userInput.body?.session_id || `session_${Date.now()}`,
      timestamp: new Date().toISOString()
    },

    // Ghost Buster Results
    image_input: {
      raw_received: rawImage ? 'present' : 'absent',
      cleaned_value: cleanedImage,
      has_valid_image: hasValidImage,
      ghost_buster_status: hasValidImage ? 'VALID_IMAGE' : 'GHOST_ELIMINATED'
    },

    detected_mode: detectedMode,
    content_type: contentType,
    vision_mode: visionMode,

    creative_params: {
      platform: platform,
      platform_specs: brandMemory.platform_specs[platform]
    },

    brand: brandMemory,
    available_products: brandMemory.products,

    // Tool availability flags
    tools_available: {
      copywriting_pro: true,
      nano_banana_pro: true,
      runway_gen3: true
    }
  }
}];

// ============================================================================
// VISION ANALYSIS - GPT-4o Image Description
// Converts image to detailed text description for downstream tools
// ============================================================================

const context = $input.first().json;
const imageBase64 = context.image_input.cleaned_value;

// For now, return a structured placeholder
// In production, this would call GPT-4o Vision API
const visionDescription = {
  scene_description: "Image received for analysis",
  dominant_colors: ["#000000", "#FFFFFF"],
  detected_objects: [],
  mood: "professional",
  text_detected: null,
  recommended_action: context.vision_mode === 'image_to_video' ? 'animate' : 'analyze'
};

return [{
  json: {
    ...context,
    vision_analysis: visionDescription,
    image_ready_for_tools: true
  }
}];

