// ============================================================================
// FORMAT UI RESPONSE - Creative MCP V6 (V12 Protocol Compliant)
// Silent Mode: No buttons unless explicit content generated
// ============================================================================

const aiOutput = $input.first().json;
let creativeData;

// ─────────────────────────────────────────────────────────────────────────
// PARSE AI OUTPUT
// ─────────────────────────────────────────────────────────────────────────
try {
  if (typeof aiOutput.output === 'string') {
    let cleanOutput = aiOutput.output
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();
    creativeData = JSON.parse(cleanOutput);
  } else if (aiOutput.output && typeof aiOutput.output === 'object') {
    creativeData = aiOutput.output;
  } else if (aiOutput.creative_result) {
    creativeData = aiOutput;
  } else {
    throw new Error('Format non reconnu');
  }
} catch (e) {
  // Fallback: Simple chat response
  creativeData = {
    creative_result: { mode: 'chat', content_produced: null },
    chat_message: { content: aiOutput.output || 'Reponse generee.', follow_up_questions: [] }
  };
}

const result = creativeData.creative_result || {};
const chatMsg = creativeData.chat_message || {};
const content = result.content_produced || {};

// ─────────────────────────────────────────────────────────────────────────
// V12 PROTOCOL: Build UI Components based on ACTUAL content produced
// ─────────────────────────────────────────────────────────────────────────

const uiComponents = [];
let uiComponentType = 'EMPTY_STATE';  // Default: no UI

// CASE 1: Video was generated -> VIDEO_PLAYER
if (content.video && content.video.url) {
  uiComponentType = 'VIDEO_PLAYER';
  uiComponents.push({
    type: 'VIDEO_PLAYER',
    data: {
      video_url: content.video.url,
      duration: content.video.duration || 4,
      type: content.video.type || 'text_to_video',
      thumbnail: content.image?.url || null,
      title: 'Video generee par Runway Gen-3',
      downloadable: true
    }
  });
}

// CASE 2: Image was generated -> AD_PREVIEW
if (content.image && content.image.url) {
  uiComponentType = uiComponentType === 'EMPTY_STATE' ? 'AD_PREVIEW' : uiComponentType;
  uiComponents.push({
    type: 'AD_PREVIEW',
    data: {
      platform: result.platform || 'meta_feed',
      format: 'feed',
      image_url: content.image.url,
      headline: content.copy?.headline || '',
      primary_text: content.copy?.body || '',
      cta: content.copy?.cta || 'En savoir plus',
      visual_description: content.image.prompt_used,
      creative_rationale: 'Genere par Nano Banana Pro'
    }
  });
}

// CASE 3: Only copy was generated -> COPY_BLOCK
if (content.copy && !content.image && !content.video) {
  uiComponentType = 'COPY_BLOCK';
  uiComponents.push({
    type: 'COPY_BLOCK',
    data: {
      headline: content.copy.headline || '',
      body: content.copy.body || '',
      cta: content.copy.cta || '',
      format: 'marketing_copy',
      copyable: true
    }
  });
}

// CASE 4: Brainstorming mode -> BATTLE_CARD (concepts)
if (result.mode === 'brainstorming' && result.recommendations?.length > 0) {
  uiComponentType = 'BATTLE_CARD';
  uiComponents.push({
    type: 'BATTLE_CARD',
    data: {
      title: 'Concepts Creatifs',
      test_hypothesis: 'Choisissez un angle a developper',
      variants: result.recommendations.map((rec, idx) => ({
        id: rec.id || `concept_${idx}`,
        name: rec.angle || 'Concept',
        badge: idx === 0 ? 'recommended' : 'alternative',
        preview: {
          headline: rec.hook,
          primary_text: rec.why_it_works
        }
      })),
      selection_prompt: 'Quel concept souhaitez-vous developper?'
    }
  });
}

// ─────────────────────────────────────────────────────────────────────────
// V12 PROTOCOL: If no content -> EMPTY_STATE (no buttons!)
// ─────────────────────────────────────────────────────────────────────────

const uiResponse = {
  thought_process: {
    step: 'Creative Production V6',
    reasoning: `Mode: ${result.mode}. Tools: ${(result.tools_used || []).join(', ') || 'none'}`,
    tools_used: result.tools_used || [],
    confidence: 0.9,
    persona_context: 'milo_v6'
  },

  chat_message: {
    content: chatMsg.content || 'Voici ma production creative.',
    tone: 'positive',
    follow_up_questions: chatMsg.follow_up_questions || []
  },

  // V12: Explicit UI control
  ui_component: uiComponentType,
  ui_components: uiComponents,

  meta: {
    agent_id: 'creative',
    timestamp: new Date().toISOString(),
    request_id: `req_milo_${Date.now()}`,
    version: 'v6',
    tools_used: result.tools_used || []
  }
};

return [{ json: uiResponse }];

// ============================================================================
// COPYWRITING PRO - Sub-workflow Tool
// Powered by GPT for production-quality marketing copy
// ============================================================================

const input = $input.first().json;

// Simulated GPT response - In production, this calls OpenAI
const generatedCopy = {
  headline: "Stop aux fees d'agence.",
  subheadline: "Votre marketing. 100% automatise.",
  body: "Vous payez 5000EUR/mois pour des resultats moyens? The Hive automatise votre marketing avec l'IA. 4 experts virtuels. Resultats en 24h.",
  cta: "Essai Gratuit",
  tone_applied: input.tone || 'bold',
  content_type: input.content_type
};

return [{ json: { success: true, copy: generatedCopy } }];

// ============================================================================
// NANO BANANA PRO - Sub-workflow Tool
// AI Image Generation (Flux/Midjourney simulation)
// ============================================================================

const input = $input.first().json;

// Simulated image generation - In production, calls Flux/Midjourney API
const generatedImage = {
  url: `https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=1080&h=1080&fit=crop&t=${Date.now()}`,
  prompt_used: input.prompt,
  style_applied: input.style || 'minimalist',
  aspect_ratio: input.aspect_ratio || '1:1',
  generation_time_ms: 3500
};

return [{ json: { success: true, image: generatedImage } }];

// ============================================================================
// RUNWAY GEN-3 ALPHA - Sub-workflow Tool
// Video Generation: Text-to-Video & Image-to-Video
// ============================================================================

const input = $input.first().json;

// Simulated Runway response - In production, calls RunwayML API
const generatedVideo = {
  url: `https://storage.runway.com/generated/${Date.now()}.mp4`,
  mode: input.mode || 'text_to_video',
  prompt_used: input.prompt,
  duration: input.duration || 4,
  resolution: '1080x1080',
  generation_time_ms: 45000,
  credits_used: 10
};

return [{ json: { success: true, video: generatedVideo } }];
